import "./App.css";
import Slider from "./Slider";
import Nav from "./nav";

function App() {
  return (
    <div className="App">
      <head></head>
      <header>
        <h3 class="tomasRadic">TOMAS RADIC</h3>
        <Nav />
      </header>
      <body>
        <h1 class="tomRadText">Hello, I am Tomas Radic, front-End developer</h1>
        <Slider number={69} />
      </body>
    </div>
  );
}

export default App;
